import React, { useEffect, useState } from 'react';
import { get } from '../api';

const tableCellStyle = {
  border: '1px solid #ccc',
  padding: '8px',
  verticalAlign: 'top',
};

const preStyle = {
  margin: 0,
  whiteSpace: 'pre-wrap',
  wordBreak: 'break-word',
  fontSize: 12,
  maxWidth: 260,
};

const changeListStyle = {
  display: 'flex',
  flexDirection: 'column',
  gap: 8,
  minWidth: 320,
};

const changeCardStyle = {
  border: '1px solid #e2e8f0',
  borderRadius: 8,
  padding: 10,
  backgroundColor: '#f8fafc',
};

const changeValueStyle = {
  marginTop: 6,
  padding: '8px 10px',
  borderRadius: 6,
  backgroundColor: '#ffffff',
  border: '1px solid #dbe4ee',
};

const highlightedValueStyle = {
  ...changeValueStyle,
  backgroundColor: '#fff5cc',
  border: '1px solid #f2c94c',
};

const parseJsonObject = (value) => {
  if (!value) {
    return {};
  }

  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' ? parsed : {};
  } catch {
    return {};
  }
};

const formatLabel = (value) => {
  if (!value) {
    return 'Details';
  }

  return String(value)
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .replace(/[_.-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/^./, (letter) => letter.toUpperCase());
};

const formatValue = (value) => {
  if (value == null || value === '') {
    return 'Empty';
  }

  if (typeof value === 'boolean') {
    return value ? 'Yes' : 'No';
  }

  if (typeof value === 'object') {
    return JSON.stringify(value);
  }

  return String(value);
};

const getChangedFields = (log) => {
  const oldValues = parseJsonObject(log.oldValues);
  const newValues = parseJsonObject(log.newValues);
  const changedColumns = (log.changedColumns || '')
    .split(',')
    .map((column) => column.trim())
    .filter(Boolean);

  const fieldNames = Array.from(new Set([
    ...changedColumns,
    ...Object.keys(oldValues),
    ...Object.keys(newValues),
  ]));

  if (fieldNames.length === 0) {
    return [];
  }

  return fieldNames.map((fieldName) => ({
    fieldName,
    label: formatLabel(fieldName),
    oldValue: formatValue(oldValues[fieldName]),
    newValue: formatValue(newValues[fieldName]),
    isChanged: JSON.stringify(oldValues[fieldName] ?? null) !== JSON.stringify(newValues[fieldName] ?? null),
  }));
};

const renderChanges = (log) => {
  const changes = getChangedFields(log);

  if (changes.length === 0) {
    return <span>No field details</span>;
  }

  return (
    <div style={changeListStyle}>
      {changes.map((change) => (
        <div key={`${log.id}-${change.fieldName}`} style={changeCardStyle}>
          <div style={{ fontWeight: 600 }}>{change.label}</div>
          <div style={{ marginTop: 8, fontSize: 12, color: '#475569' }}>Before</div>
          <div style={changeValueStyle}>{change.oldValue}</div>
          <div style={{ marginTop: 8, fontSize: 12, color: '#475569' }}>After</div>
          <div style={change.isChanged ? highlightedValueStyle : changeValueStyle}>{change.newValue}</div>
        </div>
      ))}
    </div>
  );
};

const AuditLogs = () => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchText, setSearchText] = useState('');
  const [actorTypeFilter, setActorTypeFilter] = useState('All');
  const [entityNameFilter, setEntityNameFilter] = useState('All');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');

  const loadLogs = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin-lists/audit-logs');
      setLogs(response.data);
    } catch (err) {
      console.error(err);
      setError('Unable to load audit logs.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadLogs();
  }, []);

  const actorTypes = ['All', ...new Set(logs.map((log) => log.actorType).filter(Boolean))];
  const entityNames = ['All', ...new Set(logs.map((log) => log.entityName).filter(Boolean))];

  const filteredLogs = logs.filter((log) => {
    const query = searchText.trim().toLowerCase();
    const haystack = [
      log.entityName,
      log.entityId,
      log.action,
      log.actorType,
      log.actorId,
      log.actorName,
      log.changedColumns,
      log.oldValues,
      log.newValues,
    ]
      .filter(Boolean)
      .join(' ')
      .toLowerCase();

    const matchesSearch = !query || haystack.includes(query);
    const matchesActorType = actorTypeFilter === 'All' || log.actorType === actorTypeFilter;
    const matchesEntityName = entityNameFilter === 'All' || log.entityName === entityNameFilter;

    const createdAt = new Date(log.createdAt);
    const matchesFromDate = !fromDate || createdAt >= new Date(`${fromDate}T00:00:00`);
    const matchesToDate = !toDate || createdAt <= new Date(`${toDate}T23:59:59.999`);

    return matchesSearch && matchesActorType && matchesEntityName && matchesFromDate && matchesToDate;
  });

  return (
    <div>
      <h2>Audit Logs</h2>
      <div style={{ marginBottom: 12 }}>
        <button onClick={loadLogs} disabled={loading}>
          Refresh
        </button>
      </div>
      <div style={{ marginBottom: 16 }}>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <div>
            <label style={{ display: 'block', marginBottom: 4 }}>Search</label>
            <input
              type="text"
              value={searchText}
              onChange={(e) => setSearchText(e.target.value)}
              placeholder="Search audit logs"
              style={{ width: 280 }}
            />
          </div>
          <div>
            <label style={{ display: 'block', marginBottom: 4 }}>Actor Type</label>
            <select value={actorTypeFilter} onChange={(e) => setActorTypeFilter(e.target.value)}>
              {actorTypes.map((actorType) => (
                <option key={actorType} value={actorType}>
                  {actorType}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label style={{ display: 'block', marginBottom: 4 }}>Entity Name</label>
            <select value={entityNameFilter} onChange={(e) => setEntityNameFilter(e.target.value)}>
              {entityNames.map((entityName) => (
                <option key={entityName} value={entityName}>
                  {entityName}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label style={{ display: 'block', marginBottom: 4 }}>From Date</label>
            <input type="date" value={fromDate} onChange={(e) => setFromDate(e.target.value)} />
          </div>
          <div>
            <label style={{ display: 'block', marginBottom: 4 }}>To Date</label>
            <input type="date" value={toDate} onChange={(e) => setToDate(e.target.value)} />
          </div>
        </div>
      </div>
      {loading && <p>Loading audit logs...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {!loading && !error && filteredLogs.length === 0 && <p>No audit logs found.</p>}
      {!loading && !error && filteredLogs.length > 0 && (
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                <th style={tableCellStyle}>When</th>
                <th style={tableCellStyle}>What Changed</th>
                <th style={tableCellStyle}>Action</th>
                <th style={tableCellStyle}>Done By</th>
                <th style={tableCellStyle}>Changed Details</th>
              </tr>
            </thead>
            <tbody>
              {filteredLogs.map((log) => (
                <tr key={log.id}>
                  <td style={tableCellStyle}>{new Date(log.createdAt).toLocaleString()}</td>
                  <td style={tableCellStyle}>
                    <div style={{ fontWeight: 600 }}>{formatLabel(log.entityName)}</div>
                    <div style={{ marginTop: 4, color: '#475569', fontSize: 13 }}>
                      {log.entityId ? `Record #${log.entityId}` : 'Record updated'}
                    </div>
                  </td>
                  <td style={tableCellStyle}>{log.action}</td>
                  <td style={tableCellStyle}>
                    <div style={{ fontWeight: 600 }}>{log.actorName || log.actorId || 'System'}</div>
                    <div style={{ marginTop: 4, color: '#475569', fontSize: 13 }}>{formatLabel(log.actorType)}</div>
                  </td>
                  <td style={tableCellStyle}>{renderChanges(log)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AuditLogs;
